#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e6+5;
string s;int f[MAXN];
int main(void){
	//freopen("Coin.in","r",stdin);
	//freopen("Coin.out","w",stdout);
	cin>>s;f[0]=1;
	for(int i=1;i<s.size();++i){
		if(s[i]!=s[i-1])f[i]=f[i-1]+1;
		else f[i]=f[i-1];
	}printf("%d",f[s.size()-1]);
	return false;
}
